    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? result;

    // Filter state
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // Paging & sorting
    private string currentSort = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    // UI state
    private bool isLoading = true;
    private string? errorMessage;

    private int ShowingStart => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int ShowingEnd => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);
    private int TotalPages => result is null || result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            if (categories is null)
            {
                categories = await ProductService.GetCategoriesAsync();
            }

            var filter = BuildFilter();
            result = await ProductService.SearchAsync(filter, currentSort, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
        MinPrice: minPrice,
        MaxPrice: maxPrice,
        InStockOnly: inStockOnly
    );

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        currentSort = "price_asc";
        await LoadDataAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        await Task.CompletedTask;
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        int start = Math.Max(1, currentPage - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

