+@page "/catalog"
+@using sv_cec6d642b22f4652813d82e9681378c2.Services
+@rendermode InteractiveServer
+@inject IProductService ProductService
+
+<PageTitle>Product Catalog</PageTitle>
+
+<h3 class="mb-3">Product Catalog</h3>
+
+<div class="catalog-layout d-flex gap-4">
+    @* ── Left Sidebar ── *@
+    <aside class="catalog-sidebar p-3 border rounded bg-white">
+        <h5 class="mb-3">Filters</h5>
+
+        @* Categories *@
+        <div class="mb-3">
+            <label class="form-label fw-semibold">Category</label>
+            @if (categories is not null)
+            {
+                @foreach (var cat in categories)
+                {
+                    <div class="form-check">
+                        <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
+                               checked="@selectedCategories.Contains(cat)"
+                               @onchange="e => ToggleCategory(cat, (bool)(e.Value ?? false))" />
+                        <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
+                    </div>
+                }
+            }
+            else
+            {
+                <p class="text-muted small">Loading…</p>
+            }
+        </div>
+
+        @* Price Range *@
+        <div class="mb-3">
+            <label class="form-label fw-semibold">Price Range</label>
+            <div class="d-flex gap-2 align-items-center">
+                <input type="number" class="form-control form-control-sm" placeholder="Min"
+                       @bind="minPrice" min="0" step="0.01" />
+                <span>–</span>
+                <input type="number" class="form-control form-control-sm" placeholder="Max"
+                       @bind="maxPrice" min="0" step="0.01" />
+            </div>
+        </div>
+
+        @* In Stock Only *@
+        <div class="form-check mb-3">
+            <input class="form-check-input" type="checkbox" id="inStockOnly"
+                   @bind="inStockOnly" />
+            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
+        </div>
+
+        @* Filter Buttons *@
+        <div class="d-grid gap-2">
+            <button class="btn btn-primary btn-sm" @onclick="ApplyFilters" disabled="@isLoading">
+                Apply Filters
+            </button>
+            <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters" disabled="@isLoading">
+                Clear Filters
+            </button>
+        </div>
+    </aside>
+
+    @* ── Main Content ── *@
+    <main class="catalog-main flex-grow-1">
+        @if (errorMessage is not null)
+        {
+            <div class="alert alert-danger" role="alert">
+                <strong>Error:</strong> @errorMessage
+            </div>
+        }
+        else if (isLoading)
+        {
+            <div class="d-flex justify-content-center align-items-center py-5">
+                <div class="spinner-border text-primary" role="status">
+                    <span class="visually-hidden">Loading…</span>
+                </div>
+                <span class="ms-3">Loading products…</span>
+            </div>
+        }
+        else if (result is null || result.Items.Count == 0)
+        {
+            <div class="alert alert-info text-center py-5" role="alert">
+                <h5>No products found</h5>
+                <p class="mb-0">Try adjusting your filters or clearing them to see all products.</p>
+            </div>
+        }
+        else
+        {
+            @* Toolbar *@
+            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
+                <div class="d-flex align-items-center gap-2">
+                    <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
+                    <select id="sortSelect" class="form-select form-select-sm w-auto"
+                            @bind="currentSort"
+                            @bind:after="OnSortChanged">
+                        <option value="price_asc">Price: Low to High</option>
+                        <option value="price_desc">Price: High to Low</option>
+                        <option value="name_asc">Name: A–Z</option>
+                        <option value="rating_desc">Rating: Highest</option>
+                    </select>
+                </div>
+                <span class="text-muted">
+                    Showing @ShowingStart–@ShowingEnd of @result.TotalCount products
+                </span>
+            </div>
+
+            @* Product Grid *@
+            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-4">
+                @foreach (var product in result.Items)
+                {
+                    <div class="col">
+                        <ProductCard Product="product"
+                                     OnProductSelected="HandleProductSelected"
+                                     OnAddToCart="HandleAddToCart" />
+                    </div>
+                }
+            </div>
+
+            @* Pagination *@
+            @if (TotalPages > 1)
+            {
+                <nav aria-label="Product pagination">
+                    <ul class="pagination justify-content-center">
+                        <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
+                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
+                                    disabled="@(currentPage <= 1)">
+                                Previous
+                            </button>
+                        </li>
+                        @foreach (var p in GetPageNumbers())
+                        {
+                            <li class="page-item @(p == currentPage ? "active" : "")">
+                                <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
+                            </li>
+                        }
+                        <li class="page-item @(currentPage >= TotalPages ? "disabled" : "")">
+                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
+                                    disabled="@(currentPage >= TotalPages)">
+                                Next
+                            </button>
+                        </li>
+                    </ul>
+                </nav>
+            }
+        }
+    </main>
+</div>
+
+@code {
+    [Parameter]
+    public EventCallback<Product> OnProductSelected { get; set; }
+
+    private List<string>? categories;
+    private PagedResult<Product>? result;
+
+    // Filter state
+    private HashSet<string> selectedCategories = new();
+    private decimal? minPrice;
+    private decimal? maxPrice;
+    private bool inStockOnly;
+
+    // Paging & sorting
+    private string currentSort = "price_asc";
+    private int currentPage = 1;
+    private const int PageSize = 9;
+
+    // UI state
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    private int ShowingStart => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
+    private int ShowingEnd => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);
+    private int TotalPages => result is null || result.PageSize == 0
+        ? 0
+        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadDataAsync();
+    }
+
+    private async Task LoadDataAsync()
+    {
+        isLoading = true;
+        errorMessage = null;
+
+        try
+        {
+            if (categories is null)
+            {
+                categories = await ProductService.GetCategoriesAsync();
+            }
+
+            var filter = BuildFilter();
+            result = await ProductService.SearchAsync(filter, currentSort, currentPage, PageSize);
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load products. {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private ProductFilter BuildFilter() => new(
+        Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
+        MinPrice: minPrice,
+        MaxPrice: maxPrice,
+        InStockOnly: inStockOnly
+    );
+
+    private void ToggleCategory(string category, bool isChecked)
+    {
+        if (isChecked)
+            selectedCategories.Add(category);
+        else
+            selectedCategories.Remove(category);
+    }
+
+    private async Task ApplyFilters()
+    {
+        currentPage = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task ClearFilters()
+    {
+        selectedCategories.Clear();
+        minPrice = null;
+        maxPrice = null;
+        inStockOnly = false;
+        currentPage = 1;
+        currentSort = "price_asc";
+        await LoadDataAsync();
+    }
+
+    private async Task OnSortChanged()
+    {
+        currentPage = 1;
+        await LoadDataAsync();
+    }
+
+    private async Task GoToPage(int page)
+    {
+        if (page < 1 || page > TotalPages) return;
+        currentPage = page;
+        await LoadDataAsync();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
+    private async Task HandleAddToCart(Product product)
+    {
+        // Placeholder for add-to-cart logic
+        await Task.CompletedTask;
+    }
+
+    private IEnumerable<int> GetPageNumbers()
+    {
+        const int maxVisible = 5;
+        int start = Math.Max(1, currentPage - maxVisible / 2);
+        int end = Math.Min(TotalPages, start + maxVisible - 1);
+        start = Math.Max(1, end - maxVisible + 1);
+
+        for (int i = start; i <= end; i++)
+            yield return i;
+    }
+}
